import React, { useState, memo } from 'react';
import { createPortal } from 'react-dom';
import { Instruction } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface InstructionsSectionProps {
  instructions: Instruction[];
  onAdd: (inst: Omit<Instruction, 'id' | 'updatedAt'>) => Promise<void>;
  onUpdate: (id: string, updates: Partial<Instruction>) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
  hasManagePermission: boolean;
}

const Icons = {
  Plus: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>,
  Trash: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Edit: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
  Book: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
};

const categoryOptions = ['PROD', 'LOG', 'SAFE', 'OTHER'] as const;

const InstructionsSection: React.FC<InstructionsSectionProps> = memo(({ instructions, onAdd, onUpdate, onDelete, hasManagePermission }) => {
  const { t, language } = useLanguage();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<Instruction['category']>('PROD');
  const [content, setContent] = useState('');

  const handleOpenAdd = () => {
    setTitle(''); setCategory('PROD'); setContent(''); setEditingId(null);
    setIsModalOpen(true);
  };

  const handleOpenEdit = (inst: Instruction) => {
    setTitle(inst.title); setCategory(inst.category); setContent(inst.content); setEditingId(inst.id);
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    if (!title || !content) return;
    const author = localStorage.getItem('app_user') || 'Admin';

    if (editingId) {
      await onUpdate(editingId, { title, category, content });
    } else {
      await onAdd({ title, category, content, author });
    }
    setIsModalOpen(false);
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-sm relative overflow-hidden";
  const labelClass = "block text-[9px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
  const inputClass = "w-full h-12 bg-slate-950 border border-slate-800 rounded-xl px-4 text-white text-sm font-bold focus:border-teal-500 outline-none transition-all uppercase";
  const modalOverlayClass = "fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in";
  const modalContentClass = "bg-slate-900 border-2 border-slate-700 rounded-3xl shadow-2xl w-full max-w-2xl p-8 relative";

  if (!hasManagePermission) {
      return (
          <div className="py-20 text-center bg-slate-900/40 rounded-3xl border border-slate-800 italic text-slate-500">
              {t('action_not_allowed')}
          </div>
      );
  }

  return (
    <div className={cardClass}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-10">
          <div>
              <h3 className="text-2xl font-black text-white uppercase tracking-tighter flex items-center gap-3">
                  <span className="w-2 h-8 bg-teal-500 rounded-full"></span>
                  {t('sect_instructions')}
              </h3>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1 ml-5">{instructions.length} dokumentov</p>
          </div>
          <button 
              onClick={handleOpenAdd}
              className="h-12 bg-teal-600 hover:bg-teal-500 text-white px-8 rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 font-black uppercase text-xs tracking-widest border-b-4 border-teal-800"
          >
              <Icons.Plus /> {t('inst_add_btn')}
          </button>
      </div>

      <div className="space-y-3 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
          {instructions.map(inst => (
              <div key={inst.id} className="bg-slate-950/30 p-4 rounded-2xl border border-white/5 flex justify-between items-center group hover:bg-slate-900 transition-colors">
                  <div className="flex items-center gap-4">
                      <div className="p-3 bg-slate-900 rounded-xl text-teal-500"><Icons.Book /></div>
                      <div>
                          <p className="text-sm font-black text-white uppercase tracking-tight">{inst.title}</p>
                          <div className="flex items-center gap-3 mt-1">
                              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{t(`inst_cat_${inst.category.toLowerCase()}` as any)}</span>
                              <span className="text-[8px] font-mono text-slate-700">Aktualizácia: {new Date(inst.updatedAt).toLocaleDateString()}</span>
                          </div>
                      </div>
                  </div>
                  <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleOpenEdit(inst)} className="p-2 text-slate-400 hover:text-white hover:bg-teal-600 rounded-lg"><Icons.Edit /></button>
                      <button onClick={() => { if(window.confirm('Zmazať inštrukciu?')) onDelete(inst.id); }} className="p-2 text-slate-400 hover:text-white hover:bg-red-600 rounded-lg"><Icons.Trash /></button>
                  </div>
              </div>
          ))}
          {instructions.length === 0 && (
              <div className="py-20 text-center border-2 border-dashed border-slate-800 rounded-3xl">
                  <p className="text-slate-600 font-bold uppercase tracking-widest text-xs">Žiadna dokumentácia</p>
              </div>
          )}
      </div>

      {isModalOpen && createPortal(
          <div className={modalOverlayClass} onClick={() => setIsModalOpen(false)}>
              <div className={modalContentClass} onClick={e => e.stopPropagation()}>
                  <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-8">{editingId ? t('inst_edit_title') : t('inst_new_title')}</h3>
                  <div className="space-y-6">
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                          <div>
                              <label className={labelClass}>{t('inst_label_title')}</label>
                              <input value={title} onChange={e => setTitle(e.target.value)} className={inputClass} placeholder="NAPR. BOZP SKLAD" />
                          </div>
                          <div>
                              <label className={labelClass}>{t('inst_label_cat')}</label>
                              <select value={category} onChange={e => setCategory(e.target.value as any)} className={inputClass}>
                                  {categoryOptions.map(c => <option key={c} value={c}>{t(`inst_cat_${c.toLowerCase()}` as any)}</option>)}
                              </select>
                          </div>
                      </div>
                      <div>
                          <label className={labelClass}>{t('inst_label_content')}</label>
                          <textarea 
                              value={content} 
                              onChange={e => setContent(e.target.value)} 
                              className="w-full h-64 bg-slate-950 border border-slate-800 rounded-2xl p-6 text-white text-sm focus:border-teal-500 outline-none transition-all" 
                              placeholder="Tu napíšte inštrukcie..."
                          />
                      </div>
                      <div className="grid grid-cols-2 gap-4 mt-8">
                          <button onClick={() => setIsModalOpen(false)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                          <button onClick={handleSubmit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ DOKUMENT</button>
                      </div>
                  </div>
              </div>
          </div>,
          document.body
      )}
    </div>
  );
});

export default InstructionsSection;

import React, { useState } from 'react';
import { Role } from '../../App'; 
import { useLanguage } from '../LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    onAddRole: (name: string, parentId?: string, rank?: number) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
    onVerifyAdminPassword: (password: string) => boolean;
}

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword }) => {
    const { t, language } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');
    const [selectedParentId, setSelectedParentId] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: [
              'perm_tab_entry', 
              'perm_tab_tasks', 
              'perm_tab_quick_action',
              'perm_tab_bom', 
              'perm_tab_catalog',
              'perm_tab_missing', 
              'perm_tab_inventory', 
              'perm_tab_logistics_center', 
              'perm_scrap_add',
              'perm_scrap_list',
              'perm_scrap_archive',
              'perm_tab_scrap_analytics',
              'perm_tab_instructions',
              'perm_tab_map',
              'perm_tab_logs',
              'perm_tab_erp',
              'perm_tab_analytics', 
              'perm_tab_settings', 
              'perm_tab_permissions', 
              'perm_logistics_mode'
          ] 
      },
      {
          name: 'perm_group_actions',
          perms: [
              'perm_btn_finish', 
              'perm_btn_edit', 
              'perm_btn_delete', 
              'perm_btn_resolve', 
              'perm_btn_missing', 
              'perm_scrap_edit',
              'perm_btn_copy', 
              'perm_btn_return', 
              'perm_btn_note', 
              'perm_btn_incorrect', 
              'perm_btn_lock', 
              'perm_btn_block_new', 
              'perm_btn_audit', 
              'perm_erp_manage', 
              'perm_erp_delete', 
              'perm_view_fullscreen', 
              'perm_play_sound', 
              'perm_push_notification', 
              'perm_view_passwords'
          ]
      },
      {
          name: 'perm_group_settings',
          perms: ['perm_view_setup', 'perm_settings_users', 'perm_settings_parts', 'perm_settings_wp', 'perm_settings_bom', 'perm_settings_instructions', 'perm_settings_qa_architect', 'perm_settings_csdb', 'perm_settings_system', 'perm_settings_maint']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_manage_instructions', 'perm_scrap_manage', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'] 
      }
    ];

    const hasPermission = (role: Role, permName: string) => {
        return role.permissions ? role.permissions.includes(permName) : false;
    };

    const handleCreateRole = () => {
        if (!newRoleName.trim()) return;
        const parent = roles.find(r => r.id === selectedParentId);
        const rank = parent ? (parent.rank || 0) + 1 : 5;
        onAddRole(newRoleName, selectedParentId || undefined, rank);
        setNewRoleName('');
        setSelectedParentId('');
    };

    const canDelete = (role: Role) => !role.isSystem && role.name.toUpperCase() !== 'ADMIN';

    const handleDeleteClick = (role: Role) => {
        if (!canDelete(role)) return;
        if (window.confirm(language === 'sk' ? `Naozaj chcete vymazať rolu ${role.name}?` : `Delete role ${role.name}?`)) {
            onDeleteRole(role.id);
        }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-10 pb-12 animate-fade-in relative">
            <h1 className="text-center text-3xl font-extrabold text-orange-400 mb-8 uppercase tracking-widest">{t('sect_roles')}</h1>

            {/* Role Management Header */}
            <div className="bg-gray-800 p-6 rounded-2xl border border-gray-700 shadow-xl mb-10">
                <h3 className="text-xs font-black text-gray-500 uppercase tracking-[0.2em] mb-4">Vytvoriť novú rolu</h3>
                <div className="flex flex-col md:flex-row gap-4">
                    <input 
                        type="text" 
                        value={newRoleName}
                        onChange={(e) => setNewRoleName(e.target.value)}
                        placeholder={t('role_name_place')}
                        className="flex-1 bg-gray-900 border border-gray-700 text-white px-5 py-3 rounded-xl focus:border-orange-500 outline-none font-bold uppercase placeholder-gray-600"
                    />
                    <select 
                        value={selectedParentId}
                        onChange={(e) => setSelectedParentId(e.target.value)}
                        className="md:w-64 bg-gray-900 border border-gray-700 text-white px-5 py-3 rounded-xl focus:border-orange-500 outline-none font-bold uppercase"
                    >
                        <option value="">{language === 'sk' ? 'ŽIADNY NADRIADENÝ' : 'NO PARENT ROLE'}</option>
                        {roles.map(r => (
                            <option key={r.id} value={r.id}>{r.name} (LVL {r.rank || 0})</option>
                        ))}
                    </select>
                    <button 
                        onClick={handleCreateRole}
                        className="bg-orange-600 hover:bg-orange-500 text-white font-black px-10 py-3 rounded-xl transition-all shadow-lg active:scale-95 uppercase tracking-widest text-sm"
                    >
                        {t('role_add_btn')}
                    </button>
                </div>
            </div>

            {permGroups.map(group => (
                 <div key={group.name} className="bg-gray-900 rounded-2xl p-8 border border-gray-700">
                     <h3 className="text-xl font-black text-gray-300 mb-6 border-b border-gray-700 pb-3 uppercase">{t(group.name as any)}</h3>
                     <div className="overflow-x-auto custom-scrollbar"> 
                         <table className="min-w-[700px] w-full text-left text-base">
                             <thead>
                                 <tr>
                                     <th className="py-4 px-5 text-gray-400 font-bold uppercase text-xs tracking-widest">{t('permission_label')}</th> 
                                     {roles.map(role => (
                                         <th key={role.id} className="py-4 px-5 text-white font-black text-center min-w-[120px]">
                                             <div className="flex flex-col items-center gap-1">
                                                 <span className="text-sm leading-tight">{role.name}</span>
                                                 <div className="flex items-center gap-2">
                                                     <span className="text-[9px] text-orange-500/70 uppercase font-black bg-orange-500/10 px-1.5 rounded border border-orange-500/20">LVL {role.rank || 0}</span>
                                                     <button 
                                                        onClick={() => handleDeleteClick(role)}
                                                        disabled={!canDelete(role)}
                                                        className={`transition-colors ${canDelete(role) ? 'text-gray-600 hover:text-red-500' : 'text-gray-800 cursor-not-allowed opacity-30'}`}
                                                     >
                                                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                                     </button>
                                                 </div>
                                             </div>
                                         </th>
                                     ))}
                                 </tr>
                             </thead>
                             <tbody className="divide-y divide-gray-800">
                                 {group.perms.map(perm => (
                                     <tr key={perm} className="hover:bg-gray-800/50 transition-colors">
                                         <td className="py-5 px-5 text-gray-300 font-medium">{t(perm as any)}</td>
                                         {roles.map(role => (
                                             <td key={`${role.id}-${perm}`} className="py-5 px-5 text-center">
                                                 <input 
                                                    type="checkbox" 
                                                    checked={hasPermission(role, perm)} 
                                                    onChange={(e) => onUpdatePermission && onUpdatePermission(perm, role.name, e.target.checked)} 
                                                    className="w-6 h-6 text-orange-500 bg-gray-700 border-gray-600 rounded cursor-pointer transition-transform active:scale-110" 
                                                 />
                                             </td>
                                         ))}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                 </div>
             ))}
        </div>
    );
};

export default PermissionsTab;

import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { DBItem, MapSector, PartRequest, BOMRequest, BOMComponent, MapObstacle, CSItem, QuickActionConfig, Instruction } from '../../types/appTypes';

export const useMasterData = () => {
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]);
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [mapObstacles, setMapObstacles] = useState<MapObstacle[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [quickActions, setQuickActions] = useState<QuickActionConfig[]>([]);
  const [instructions, setInstructions] = useState<Instruction[]>([]);

  const [customers, setCustomers] = useState<CSItem[]>([]);
  const [suppliers, setSuppliers] = useState<CSItem[]>([]);

  useEffect(() => {
    const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
        const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
        setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
    });
    const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
    const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));

    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, BOMComponent[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubQuickActions = onSnapshot(doc(db, 'settings', 'quick_actions'), (s) => {
        setQuickActions(s.exists() ? (s.data().items || []) : []);
    });

    const unsubObstacles = onSnapshot(doc(db, 'settings', 'map_layout'), (docSnap) => {
        if (docSnap.exists()) {
            setMapObstacles(docSnap.data().obstacles || []);
        } else {
            setMapObstacles([]);
        }
    });

    const unsubCustomers = onSnapshot(doc(db, 'CSDB', 'customers'), (s) => {
        setCustomers(s.exists() ? (s.data().items || []) : []);
    });
    const unsubSuppliers = onSnapshot(doc(db, 'CSDB', 'suppliers'), (s) => {
        setSuppliers(s.exists() ? (s.data().items || []) : []);
    });

    const unsubInstructions = onSnapshot(doc(db, 'settings', 'instructions'), (s) => {
      setInstructions(s.exists() ? (s.data().items || []) : []);
    });

    return () => { 
        unsubWp(); unsubLogOps(); unsubSectors(); unsubPartReq(); unsubBomReq();
        unsubParts(); unsubBOM(); unsubObstacles();
        unsubCustomers(); unsubSuppliers(); unsubQuickActions();
        unsubInstructions();
    };
  }, []);

  const onAddInstruction = async (inst: Omit<Instruction, 'id' | 'updatedAt'>) => {
    const newItem = { ...inst, id: crypto.randomUUID(), updatedAt: Date.now() };
    await setDoc(doc(db, 'settings', 'instructions'), { items: arrayUnion(newItem) }, { merge: true });
  };

  const onUpdateInstruction = async (id: string, updates: Partial<Instruction>) => {
    const ref = doc(db, 'settings', 'instructions');
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const items = snap.data().items || [];
      const newItems = items.map((i: any) => i.id === id ? { ...i, ...updates, updatedAt: Date.now() } : i);
      await updateDoc(ref, { items: newItems });
    }
  };

  const onDeleteInstruction = async (id: string) => {
    const ref = doc(db, 'settings', 'instructions');
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const items = snap.data().items || [];
      const newItems = items.filter((i: any) => i.id !== id);
      await updateDoc(ref, { items: newItems });
    }
  };

  const onAddQuickAction = async (config: Omit<QuickActionConfig, 'id'>) => {
      const newAction = { ...config, id: crypto.randomUUID() };
      await setDoc(doc(db, 'settings', 'quick_actions'), { items: arrayUnion(newAction) }, { merge: true });
  };

  const onUpdateQuickAction = async (id: string, updates: Partial<QuickActionConfig>) => {
      const ref = doc(db, 'settings', 'quick_actions');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const currentItems = snap.data().items || [];
          const newItems = currentItems.map((i: any) => i.id === id ? { ...i, ...updates } : i);
          await updateDoc(ref, { items: newItems });
      }
  };

  const onDeleteQuickAction = async (id: string) => {
      const ref = doc(db, 'settings', 'quick_actions');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().items || []).filter((i: any) => i.id !== id);
          await updateDoc(ref, { items: filtered });
      }
  };

  // CSDB Actions
  const onAddCSItem = async (category: 'customers' | 'suppliers', name: string, description: string = '') => {
      try {
          const newItem: CSItem = { id: crypto.randomUUID(), name: name.toUpperCase(), description };
          await setDoc(doc(db, 'CSDB', category), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onBatchAddCSItems = async (category: 'customers' | 'suppliers', lines: string[]) => {
      try {
          const itemsToAdd = lines.map(line => {
              if (!line.trim()) return null;
              const [n, d] = line.split(';');
              return { id: crypto.randomUUID(), name: n.trim().toUpperCase(), description: d ? d.trim() : '' };
          }).filter(Boolean);
          if (itemsToAdd.length > 0) {
              await setDoc(doc(db, 'CSDB', category), { items: arrayUnion(...itemsToAdd) }, { merge: true });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteCSItem = async (category: 'customers' | 'suppliers', id: string) => {
      try {
          const ref = doc(db, 'CSDB', category);
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const current = snap.data().items || [];
              const filtered = current.filter((i: any) => i.id !== id);
              await updateDoc(ref, { items: filtered });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteAllCSItems = async (category: 'customers' | 'suppliers') => {
      try { await setDoc(doc(db, 'CSDB', category), { items: [] }); } catch (e) { console.error(e); }
  };

  // Obstacles
  const onAddMapObstacle = async (obs: Omit<MapObstacle, 'id'>) => {
      const id = `obs_${Date.now()}`;
      await setDoc(doc(db, 'settings', 'map_layout'), { 
          obstacles: arrayUnion({ ...obs, id }) 
      }, { merge: true });
  };
  const onDeleteMapObstacle = async (id: string) => {
      const ref = doc(db, 'settings', 'map_layout');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().obstacles || []).filter((o: any) => o.id !== id);
          await updateDoc(ref, { obstacles: filtered });
      }
  };

  // Workplaces
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0, x: number = 0, y: number = 0, defaultSource?: string | null, defaultTarget?: string | null) => { 
      await addDoc(collection(db, 'logistics_operations'), { 
          value: val, 
          standardTime: time, 
          distancePx: dist, 
          coordX: x, 
          coordY: y,
          defaultSourceSectorId: defaultSource || null,
          defaultTargetSectorId: defaultTarget || null
      }); 
  };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { 
      await updateDoc(doc(db, 'logistics_operations', id), updates); 
  };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onDeleteAllLogisticsOperations = async () => {
      const snap = await getDocs(collection(db, 'logistics_operations'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  // Parts (Single Doc Pattern)
  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { 
            value: value.toUpperCase(), 
            description 
          };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { 
          itemsToAdd.push({ 
            value: p.trim().toUpperCase(), 
            description: d ? d.trim() : '' 
          }); 
        }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };
  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };
  const onDeleteAllParts = async () => { try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); } };

  // BOM (Single Doc Pattern - Optimized for Quota Guard)
  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = { 
              parent: parent.toUpperCase(), 
              child: child.toUpperCase(), 
              consumption: qty 
          };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { 
                  itemsToAdd.push({ 
                      parent: p.trim().toUpperCase(), 
                      child: c.trim().toUpperCase(), 
                      consumption: parseFloat(q?.replace(',', '.') || '0') 
                  }); 
              }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  // Fix: changed 'error' to 'e' in catch block to match catch parameter.
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error(e); } };

  // Requests
  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeletePartRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'part_requests', id)); } catch(e) { console.error(e); }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeleteBOMRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'bom_requests', id)); } catch(e) { console.error(e); }
  };

  return {
    partsMap, bomMap, workplaces, logisticsOperations, mapSectors, mapObstacles, partRequests, bomRequests,
    customers, suppliers, quickActions, instructions,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation, onDeleteAllLogisticsOperations,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddMapObstacle, onDeleteMapObstacle,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onAddCSItem, onBatchAddCSItems, onDeleteCSItem, onDeleteAllCSItems,
    onAddQuickAction, onUpdateQuickAction, onDeleteQuickAction,
    onAddInstruction, onUpdateInstruction, onDeleteInstruction,
    onRequestPart, onDeletePartRequest, 
    onRequestBOM, onDeleteBOMRequest
  };
};

import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import { Instruction } from '../../types/appTypes';

const Icons = {
  Search: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>,
  Book: () => <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>,
  Close: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
};

const categoryColors = {
  PROD: 'border-pink-500 text-pink-400 bg-pink-500/10',
  LOG: 'border-indigo-500 text-indigo-400 bg-indigo-500/10',
  SAFE: 'border-amber-500 text-amber-400 bg-amber-500/10',
  OTHER: 'border-slate-500 text-slate-400 bg-slate-500/10'
};

const InstructionsTab: React.FC = () => {
    const { t, language } = useLanguage();
    const { instructions } = useData();

    const [searchQuery, setSearchQuery] = useState('');
    const [activeFilter, setActiveFilter] = useState<'ALL' | Instruction['category']>('ALL');
    const [selectedInst, setSelectedInst] = useState<Instruction | null>(null);

    const filtered = useMemo(() => {
        let items = [...instructions];
        if (activeFilter !== 'ALL') items = items.filter(i => i.category === activeFilter);
        if (searchQuery) {
            const q = searchQuery.toLowerCase();
            items = items.filter(i => 
              (i.title || '').toLowerCase().includes(q) || 
              (i.content || '').toLowerCase().includes(q)
            );
        }
        return items.sort((a,b) => b.updatedAt - a.updatedAt);
    }, [instructions, activeFilter, searchQuery]);

    const formatContent = (text: string) => {
        if (!text) return null;
        return text.split('\n').map((line, idx) => (
            <React.Fragment key={idx}>
                {line}
                <br />
            </React.Fragment>
        ));
    };

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
            {/* SEARCH & FILTERS */}
            <div className="bg-slate-900 border border-slate-700 rounded-3xl p-6 shadow-2xl space-y-6">
                <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="relative w-full md:w-[400px]">
                        <input 
                            type="text" 
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                            placeholder={language === 'sk' ? "Hľadať v dokumentácii..." : "Search documentation..."}
                            className="w-full h-14 bg-slate-950 border border-slate-700 rounded-2xl pl-14 pr-6 text-white font-bold uppercase focus:border-teal-500 outline-none transition-all shadow-inner"
                        />
                        <div className="absolute left-5 top-4.5 text-slate-600"><Icons.Search /></div>
                    </div>

                    <div className="flex flex-wrap gap-2 justify-center">
                        {(['ALL', 'PROD', 'LOG', 'SAFE', 'OTHER'] as const).map(cat => (
                            <button
                                key={cat}
                                onClick={() => setActiveFilter(cat)}
                                className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border-2 transition-all ${activeFilter === cat ? 'bg-teal-600 border-teal-500 text-white shadow-lg shadow-teal-900/20' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                            >
                                {cat === 'ALL' ? 'VŠETKO' : t(`inst_cat_${cat.toLowerCase()}` as any)}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* GRID */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filtered.map(inst => (
                    <div 
                        key={inst.id}
                        onClick={() => setSelectedInst(inst)}
                        className="bg-slate-900/40 border border-slate-800 rounded-3xl p-6 shadow-xl hover:border-teal-500/50 hover:bg-slate-800/40 transition-all cursor-pointer group flex flex-col min-h-[220px]"
                    >
                        <div className="flex justify-between items-start mb-4">
                            <span className={`px-2 py-0.5 rounded border text-[8px] font-black uppercase tracking-widest ${categoryColors[inst.category] || categoryColors.OTHER}`}>
                                {t(`inst_cat_${(inst.category || 'OTHER').toLowerCase()}` as any)}
                            </span>
                            <span className="text-[9px] font-mono text-slate-600">ID: {(inst.id || '').slice(0,4)}</span>
                        </div>
                        <h3 className="text-xl font-black text-white uppercase tracking-tighter leading-tight group-hover:text-teal-400 transition-colors mb-4 line-clamp-2">
                            {inst.title}
                        </h3>
                        <p className="text-xs text-slate-500 leading-relaxed line-clamp-3 italic mb-auto">
                            {inst.content}
                        </p>
                        <div className="mt-6 pt-4 border-t border-white/5 flex justify-between items-center">
                            <span className="text-[9px] font-bold text-slate-600 uppercase">{inst.updatedAt ? new Date(inst.updatedAt).toLocaleDateString() : '-'}</span>
                            <span className="text-[10px] font-black text-teal-500 uppercase tracking-widest flex items-center gap-1 group-hover:translate-x-1 transition-transform">ČÍTAŤ <span className="text-lg">→</span></span>
                        </div>
                    </div>
                ))}

                {filtered.length === 0 && (
                    <div className="col-span-full py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <div className="flex flex-col items-center gap-4">
                            <div className="p-4 bg-slate-800/50 rounded-full text-slate-700"><Icons.Book /></div>
                            <p className="text-slate-600 font-black uppercase tracking-[0.3em] text-xs">Dokumentácia nie je k dispozícii</p>
                        </div>
                    </div>
                )}
            </div>

            {/* DETAIL MODAL */}
            {selectedInst && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/95 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setSelectedInst(null)}>
                    <div className="bg-slate-900 border-2 border-slate-800 rounded-[2.5rem] shadow-[0_0_100px_rgba(0,0,0,0.8)] w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col relative" onClick={e => e.stopPropagation()}>
                        <div className="p-8 sm:p-12 border-b border-white/5 bg-slate-950/40 flex justify-between items-start gap-8">
                            <div className="space-y-4">
                                <span className={`px-3 py-1 rounded-full border text-[10px] font-black uppercase tracking-widest ${categoryColors[selectedInst.category] || categoryColors.OTHER}`}>
                                    {t(`inst_cat_${(selectedInst.category || 'OTHER').toLowerCase()}` as any)}
                                </span>
                                <h2 className="text-3xl sm:text-4xl font-black text-white uppercase tracking-tighter leading-tight">{selectedInst.title}</h2>
                                <div className="flex items-center gap-6">
                                    <div className="flex items-center gap-2">
                                        <span className="text-[9px] font-black text-slate-600 uppercase">Autor:</span>
                                        <span className="text-xs font-bold text-teal-500 uppercase">{selectedInst.author}</span>
                                    </div>
                                    <div className="flex items-center gap-2 border-l border-white/10 pl-6">
                                        <span className="text-[9px] font-black text-slate-600 uppercase">Aktualizácia:</span>
                                        <span className="text-xs font-mono font-bold text-slate-400">{selectedInst.updatedAt ? new Date(selectedInst.updatedAt).toLocaleDateString('sk-SK') : '-'}</span>
                                    </div>
                                </div>
                            </div>
                            <button onClick={() => setSelectedInst(null)} className="p-3 bg-slate-800 hover:bg-slate-700 text-slate-400 hover:text-white rounded-2xl transition-all shadow-lg active:scale-90 flex-shrink-0">
                                <Icons.Close />
                            </button>
                        </div>

                        <div className="flex-grow overflow-y-auto p-8 sm:p-12 custom-scrollbar">
                            <div className="text-lg sm:text-xl text-slate-300 leading-relaxed font-medium">
                                {formatContent(selectedInst.content)}
                            </div>
                        </div>

                        <div className="p-8 bg-slate-950/40 border-t border-white/5 flex justify-end">
                            <button 
                                onClick={() => setSelectedInst(null)}
                                className="px-10 py-4 bg-white text-slate-900 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-200 transition-all active:scale-95 shadow-xl"
                            >
                                ZAVRIEŤ DOKUMENT
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InstructionsTab;

import React, { useState, memo } from 'react';
import { createPortal } from 'react-dom';
import { Instruction } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface InstructionsSectionProps {
  instructions: Instruction[];
  onAdd: (inst: Omit<Instruction, 'id' | 'updatedAt'>) => Promise<void>;
  onUpdate: (id: string, updates: Partial<Instruction>) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
  hasManagePermission: boolean;
}

const Icons = {
  Plus: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>,
  Trash: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Edit: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
  Book: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
};

const categoryOptions = ['PROD', 'LOG', 'SAFE', 'OTHER'] as const;

const InstructionsSection: React.FC<InstructionsSectionProps> = memo(({ instructions, onAdd, onUpdate, onDelete, hasManagePermission }) => {
  const { t, language } = useLanguage();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<Instruction['category']>('PROD');
  const [content, setContent] = useState('');

  const handleOpenAdd = () => {
    setTitle(''); setCategory('PROD'); setContent(''); setEditingId(null);
    setIsModalOpen(true);
  };

  const handleOpenEdit = (inst: Instruction) => {
    setTitle(inst.title || ''); 
    setCategory(inst.category || 'PROD'); 
    setContent(inst.content || ''); 
    setEditingId(inst.id);
    setIsModalOpen(true);
  };

  const handleSubmit = async () => {
    if (!title || !content) return;
    const author = localStorage.getItem('app_user') || 'Admin';

    if (editingId) {
      await onUpdate(editingId, { title, category, content });
    } else {
      await onAdd({ title, category, content, author });
    }
    setIsModalOpen(false);
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-sm relative overflow-hidden";
  const labelClass = "block text-[9px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
  const inputClass = "w-full h-12 bg-slate-950 border border-slate-800 rounded-xl px-4 text-white text-sm font-bold focus:border-teal-500 outline-none transition-all uppercase";
  const modalOverlayClass = "fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in";
  const modalContentClass = "bg-slate-900 border-2 border-slate-700 rounded-3xl shadow-2xl w-full max-w-2xl p-8 relative";

  if (!hasManagePermission) {
      return (
          <div className="py-20 text-center bg-slate-900/40 rounded-3xl border border-slate-800 italic text-slate-500">
              {t('action_not_allowed')}
          </div>
      );
  }

  return (
    <div className={cardClass}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-10">
          <div>
              <h3 className="text-2xl font-black text-white uppercase tracking-tighter flex items-center gap-3">
                  <span className="w-2 h-8 bg-teal-500 rounded-full"></span>
                  {t('sect_instructions')}
              </h3>
              <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1 ml-5">{instructions.length} dokumentov</p>
          </div>
          <button 
              onClick={handleOpenAdd}
              className="h-12 bg-teal-600 hover:bg-teal-500 text-white px-8 rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 font-black uppercase text-xs tracking-widest border-b-4 border-teal-800"
          >
              <Icons.Plus /> {t('inst_add_btn')}
          </button>
      </div>

      <div className="space-y-3 max-h-[600px] overflow-y-auto custom-scrollbar pr-2">
          {instructions.map(inst => (
              <div key={inst.id} className="bg-slate-950/30 p-4 rounded-2xl border border-white/5 flex justify-between items-center group hover:bg-slate-900 transition-colors">
                  <div className="flex items-center gap-4">
                      <div className="p-3 bg-slate-900 rounded-xl text-teal-500"><Icons.Book /></div>
                      <div>
                          <p className="text-sm font-black text-white uppercase tracking-tight">{inst.title}</p>
                          <div className="flex items-center gap-3 mt-1">
                              <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">
                                {t(`inst_cat_${(inst.category || 'OTHER').toLowerCase()}` as any)}
                              </span>
                              <span className="text-[8px] font-mono text-slate-700">Aktualizácia: {inst.updatedAt ? new Date(inst.updatedAt).toLocaleDateString() : '-'}</span>
                          </div>
                      </div>
                  </div>
                  <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleOpenEdit(inst)} className="p-2 text-slate-400 hover:text-white hover:bg-teal-600 rounded-lg"><Icons.Edit /></button>
                      <button onClick={() => { if(window.confirm('Zmazať inštrukciu?')) onDelete(inst.id); }} className="p-2 text-slate-400 hover:text-white hover:bg-red-600 rounded-lg"><Icons.Trash /></button>
                  </div>
              </div>
          ))}
          {instructions.length === 0 && (
              <div className="py-20 text-center border-2 border-dashed border-slate-800 rounded-3xl">
                  <p className="text-slate-600 font-bold uppercase tracking-widest text-xs">Žiadna dokumentácia</p>
              </div>
          )}
      </div>

      {isModalOpen && createPortal(
          <div className={modalOverlayClass} onClick={() => setIsModalOpen(false)}>
              <div className={modalContentClass} onClick={e => e.stopPropagation()}>
                  <h3 className="text-2xl font-black text-white uppercase tracking-tighter mb-8">{editingId ? t('inst_edit_title') : t('inst_new_title')}</h3>
                  <div className="space-y-6">
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                          <div>
                              <label className={labelClass}>{t('inst_label_title')}</label>
                              <input value={title} onChange={e => setTitle(e.target.value)} className={inputClass} placeholder="NAPR. BOZP SKLAD" />
                          </div>
                          <div>
                              <label className={labelClass}>{t('inst_label_cat')}</label>
                              <select value={category} onChange={e => setCategory(e.target.value as any)} className={inputClass}>
                                  {categoryOptions.map(c => <option key={c} value={c}>{t(`inst_cat_${c.toLowerCase()}` as any)}</option>)}
                              </select>
                          </div>
                      </div>
                      <div>
                          <label className={labelClass}>{t('inst_label_content')}</label>
                          <textarea 
                              value={content} 
                              onChange={e => setContent(e.target.value)} 
                              className="w-full h-64 bg-slate-950 border border-slate-800 rounded-2xl p-6 text-white text-sm focus:border-teal-500 outline-none transition-all" 
                              placeholder="Tu napíšte inštrukcie..."
                          />
                      </div>
                      <div className="grid grid-cols-2 gap-4 mt-8">
                          <button onClick={() => setIsModalOpen(false)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                          <button onClick={handleSubmit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ DOKUMENT</button>
                      </div>
                  </div>
              </div>
          </div>,
          document.body
      )}
    </div>
  );
});

export default InstructionsSection;

import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import { QuickActionConfig } from '../../types/appTypes';
import PartNumberInput from '../PartNumberInput';

const QuickActionTab: React.FC = () => {
    const { t, language } = useLanguage();
    const data = useData();

    const [activeAction, setActiveAction] = useState<QuickActionConfig | null>(null);
    const [inputValue, setInputValue] = useState('');
    const [partnerSearch, setPartnerSearch] = useState('');
    const [qty, setQty] = useState('1');
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Filter and SORT partners alphabetically based on search input
    const filteredPartners = useMemo(() => {
        if (!activeAction) return [];
        const items = activeAction.inputType === 'CUSTOMER' ? data.customers : data.suppliers;

        // 1. Filtrácia
        const q = partnerSearch.toLowerCase().trim();
        const filtered = q 
            ? items.filter(i => 
                (i.name || '').toLowerCase().includes(q) || 
                (i.description && i.description.toLowerCase().includes(q))
              )
            : [...items];

        // 2. Abecedné zoradenie (A-Z)
        return filtered.sort((a, b) => (a.name || '').localeCompare(b.name || '', language === 'sk' ? 'sk' : 'en'));
    }, [activeAction, partnerSearch, data.customers, data.suppliers, language]);

    const handleActionClick = (action: QuickActionConfig) => {
        // AK IDE O ACTIVITY - Vynechávame modal a hneď ukladáme
        if (action.inputType === 'ACTIVITY') {
            handleImmediateSubmit(action);
            return;
        }

        setActiveAction(action);
        setInputValue(action.defaultText || '');
        setPartnerSearch('');
        setQty('1');
    };

    const handleClose = () => {
        setActiveAction(null);
        setInputValue('');
        setPartnerSearch('');
        setQty('1');
    };

    const handleImmediateSubmit = async (action: QuickActionConfig) => {
        setIsSubmitting(true);
        try {
            const op = data.logisticsOperations.find(o => o.id === action.logisticsOpId);
            await data.onAddTask(
                (action.defaultText || action.label).toUpperCase(),
                op?.value || 'Support Activity',
                '1',
                'pcs',
                'NORMAL',
                true,
                action.label, 
                false,
                action.sourceSectorId || op?.defaultSourceSectorId,
                action.targetSectorId || op?.defaultTargetSectorId,
                true, // startNow
                true  // isActivity
            );
            // Alert odstránený na žiadosť používateľa
        } catch (e) {
            console.error(e);
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSubmit = async () => {
        if (!activeAction || !inputValue || !qty) {
            alert(t('fill_all_fields'));
            return;
        }

        setIsSubmitting(true);
        try {
            const op = data.logisticsOperations.find(o => o.id === activeAction.logisticsOpId);

            await data.onAddTask(
                inputValue.toUpperCase(),
                op?.value || 'LOGISTIKA',
                qty,
                'pallet',
                'NORMAL',
                true,
                activeAction.label, 
                false,
                activeAction.sourceSectorId || op?.defaultSourceSectorId,
                activeAction.targetSectorId || op?.defaultTargetSectorId,
                true, // startNow parameter
                false // isActivity
            );

            handleClose();
        } catch (e) {
            console.error(e);
            alert("Chyba pri vytváraní rýchlej akcie.");
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
            {/* HERO SECTION */}
            <div className="bg-slate-900 border border-slate-700 rounded-[2.5rem] p-8 shadow-2xl flex flex-col md:flex-row items-center gap-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-fuchsia-500/5 rounded-full -mr-32 -mt-32 blur-3xl pointer-events-none"></div>
                <div className="w-20 h-20 bg-fuchsia-500/10 rounded-3xl flex items-center justify-center border-2 border-fuchsia-500/30 flex-shrink-0 shadow-lg">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-fuchsia-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                    </svg>
                </div>
                <div className="text-center md:text-left">
                    <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('tab_quick_action')}</h2>
                    <p className="text-slate-500 font-bold uppercase tracking-widest text-xs mt-2">Bleskové vytváranie a preberanie logistických úloh</p>
                </div>
            </div>

            {/* BUTTON GRID */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {data.quickActions.map(action => (
                    <button
                        key={action.id}
                        onClick={() => handleActionClick(action)}
                        disabled={isSubmitting}
                        className={`group relative h-44 rounded-[2rem] border-2 border-white/5 ${action.color} shadow-xl hover:scale-[1.02] active:scale-95 transition-all flex flex-col items-center justify-center p-8 text-center`}
                    >
                        <div className="absolute inset-0 bg-black opacity-0 group-hover:opacity-10 transition-opacity rounded-[2rem]"></div>
                        <span className="text-xl font-black text-white uppercase leading-tight tracking-tighter group-hover:scale-110 transition-transform drop-shadow-lg">
                            {action.label}
                        </span>
                        <div className="mt-4 flex items-center gap-2">
                             <span className="bg-white/20 px-3 py-1 rounded-full text-[9px] font-black text-white uppercase tracking-widest">
                                {data.logisticsOperations.find(o => o.id === action.logisticsOpId)?.value || 'Logistika'}
                             </span>
                             {action.inputType === 'ACTIVITY' && (
                                <span className="bg-black/40 px-2 py-0.5 rounded text-[8px] font-black text-white uppercase">Support Activity</span>
                             )}
                        </div>
                        <div className="absolute bottom-4 opacity-30 text-white group-hover:opacity-100 transition-opacity">
                            {action.inputType === 'ACTIVITY' ? (
                                <svg className="w-5 h-5 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                            ) : (
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
                            )}
                        </div>
                    </button>
                ))}

                {data.quickActions.length === 0 && (
                    <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-800 rounded-[2.5rem] opacity-40">
                         <p className="text-slate-500 font-black uppercase tracking-[0.3em] text-xs">Žiadne definované akcie. Kontaktujte Administrátora.</p>
                    </div>
                )}
            </div>

            {/* ACTION MODAL */}
            {activeAction && createPortal(
                <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in" onClick={handleClose}>
                    <div className="bg-slate-900 border-2 border-slate-700 rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,0.5)] w-full max-w-2xl overflow-hidden relative" onClick={e => e.stopPropagation()}>
                        <div className={`h-4 ${activeAction.color} border-b border-white/10`}></div>

                        <div className="p-8 sm:p-10 space-y-8 sm:space-y-10">
                            <div className="text-center">
                                <h3 className="text-3xl font-black text-white uppercase tracking-tighter leading-none mb-2">{activeAction.label}</h3>
                                <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Vytvoriť a spustiť úlohu</p>
                            </div>

                            <div className="space-y-8">
                                {/* DYNAMIC INPUT */}
                                <div>
                                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 ml-1">
                                        {activeAction.inputType === 'PART' ? 'ČÍSLO DIELU' : 
                                         activeAction.inputType === 'CUSTOMER' ? 'VÝBER ZÁKAZNÍKA' :
                                         activeAction.inputType === 'SUPPLIER' ? 'VÝBER DODÁVATEĽA' : 'TEXTOVÁ REFERENCIA'}
                                    </label>

                                    {activeAction.inputType === 'PART' ? (
                                        <PartNumberInput 
                                            parts={Object.keys(data.partsMap)}
                                            value={inputValue}
                                            onPartSelect={(v) => setInputValue(v || '')}
                                            onInputChange={(v) => setInputValue(v.toUpperCase())}
                                            placeholder="NAPR. 3323..."
                                        />
                                    ) : activeAction.inputType === 'CUSTOMER' || activeAction.inputType === 'SUPPLIER' ? (
                                        <div className="space-y-4">
                                            <div className="relative">
                                                <input 
                                                    type="text"
                                                    value={partnerSearch}
                                                    onChange={e => setPartnerSearch(e.target.value.toUpperCase())}
                                                    placeholder="HĽADAŤ V ZOZNAME..."
                                                    className="w-full h-12 bg-slate-950 border-2 border-slate-800 rounded-xl px-4 pl-12 text-white font-bold uppercase focus:border-fuchsia-500 outline-none transition-all"
                                                    autoFocus
                                                />
                                                <svg className="absolute left-4 top-3.5 h-5 w-5 text-slate-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                                            </div>

                                            <div className="max-h-[300px] overflow-y-auto custom-scrollbar border-2 border-slate-800 rounded-2xl bg-slate-950 p-2 space-y-1">
                                                {filteredPartners.map(item => (
                                                    <button
                                                        key={item.id}
                                                        onClick={() => setInputValue(item.name)}
                                                        className={`w-full py-5 px-6 rounded-xl font-black uppercase text-sm transition-all text-left flex items-center justify-between border-2 ${inputValue === item.name ? `text-white ${activeAction.color} border-white/20 shadow-lg scale-[1.02]` : 'bg-slate-900 text-white border-white/5 hover:bg-slate-800 hover:border-white/10'}`}
                                                    >
                                                        <span className="truncate">{item.name}</span>
                                                        {inputValue === item.name && <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>}
                                                    </button>
                                                ))}
                                                {filteredPartners.length === 0 && (
                                                    <div className="py-10 text-center opacity-30">
                                                        <p className="text-xs font-black uppercase tracking-widest">Nič sa nenašlo</p>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    ) : (
                                        <input 
                                            value={inputValue} 
                                            onChange={e => setInputValue(e.target.value.toUpperCase())}
                                            className="w-full h-16 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 text-white font-black uppercase text-xl focus:border-fuchsia-500 outline-none transition-all shadow-inner"
                                            placeholder="..."
                                            autoFocus
                                        />
                                    )}
                                </div>

                                {/* QUANTITY */}
                                <div>
                                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 ml-1">POČET PALIET</label>
                                    <div className="flex gap-4">
                                        {[1, 2, 3, 4, 5].map(n => (
                                            <button 
                                                key={n} 
                                                onClick={() => setQty(String(n))}
                                                className={`flex-1 h-14 rounded-xl font-black text-xl transition-all border-2 ${qty === String(n) ? 'bg-fuchsia-600 border-fuchsia-500 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                                            >
                                                {n}
                                            </button>
                                        ))}
                                        <input 
                                            type="number"
                                            value={qty}
                                            onChange={e => setQty(e.target.value)}
                                            className="w-20 h-14 bg-slate-950 border-2 border-slate-800 rounded-xl px-2 text-center text-white font-black text-xl focus:border-fuchsia-500 outline-none"
                                            placeholder="+"
                                        />
                                    </div>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4 pt-6">
                                <button 
                                    onClick={handleClose}
                                    className="h-16 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all active:scale-95"
                                >
                                    ZRUŠIŤ
                                </button>
                                <button 
                                    onClick={handleSubmit}
                                    disabled={isSubmitting || !inputValue}
                                    className={`h-16 ${activeAction.color} hover:brightness-110 disabled:opacity-30 text-white rounded-2xl font-black uppercase text-sm tracking-[0.2em] border-b-4 border-black/30 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3`}
                                >
                                    {isSubmitting ? '...' : <><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg> ODOSLAŤ A SPUSTIŤ</>}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

