import React, { useState, useEffect, useRef, useMemo, memo } from 'react';
import { useLanguage } from './LanguageContext';
import { db } from '../firebase';
import { doc, getDoc } from 'firebase/firestore';

interface PartNumberInputProps {
  parts: string[];
  onPartSelect: (part: string | null) => void;
  onInputChange?: (value: string) => void;
  placeholder?: string;
  value: string | null;
  onRequestPart?: (part: string) => Promise<boolean>;
  inputRef?: React.RefObject<HTMLInputElement>;
  onKeyDown?: React.KeyboardEventHandler<HTMLInputElement>;
}

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const GlobeIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9" />
    </svg>
);

const PartNumberInput: React.FC<PartNumberInputProps> = memo(({ parts, onPartSelect, onInputChange, placeholder, value, onRequestPart, inputRef, onKeyDown }) => {
  const [query, setQuery] = useState<string>('');
  const [isDropdownVisible, setIsDropdownVisible] = useState<boolean>(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const { t } = useLanguage();

  const [reportStatus, setReportStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [masterSearchStatus, setMasterSearchStatus] = useState<'idle' | 'loading' | 'found' | 'not_found'>('idle');

  useEffect(() => {
    setQuery(value || '');
  }, [value]);

  const filteredParts = useMemo(() => {
    const trimmedQuery = query.trim();
    if (trimmedQuery === '') return (parts || []).slice(0, 50);

    const q = trimmedQuery.toLowerCase();
    // Wildcard search support
    if (q.includes('*')) {
      const regexStr = q.replace(/\*/g, '.*');
      const regex = new RegExp(`^${regexStr}`, 'i');
      return (parts || []).filter(p => p && regex.test(p)).slice(0, 50);
    }

    return (parts || []).filter(p => p && p.toLowerCase().includes(q)).slice(0, 50);
  }, [query, parts]);

  useEffect(() => {
    setReportStatus('idle');
    setMasterSearchStatus('idle');
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsDropdownVisible(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelectPart = (part: string) => {
    setQuery(part);
    onPartSelect(part);
    if (onInputChange) onInputChange(part);
    setIsDropdownVisible(false);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setQuery(newValue);
    if (onInputChange) onInputChange(newValue);

    const exactMatch = (parts || []).find(p => p && p.toLowerCase() === newValue.trim().toLowerCase());
    if (exactMatch) {
      onPartSelect(exactMatch);
    } else {
      onPartSelect(null);
    }
  };

  const handleInternalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      // Okamžite schováme dropdown pri stlačení Enteru pre navigáciu
      setIsDropdownVisible(false);
    }
    if (onKeyDown) onKeyDown(e);
  };

  const handleRequestClick = async (e: React.MouseEvent) => {
    e.preventDefault();
    if (onRequestPart && query.trim()) {
        setReportStatus('loading');
        const success = await onRequestPart(query.trim());
        if (success) {
            setReportStatus('success');
            setIsDropdownVisible(false);
            setTimeout(() => setReportStatus('idle'), 3000);
        } else {
            setReportStatus('idle');
        }
    }
  };

  // --- NOVINKA: Master DB Lookup ---
  const handleMasterLookup = async (e: React.MouseEvent) => {
      e.preventDefault();
      const partToFind = query.trim().toUpperCase();
      if (!partToFind) return;

      setMasterSearchStatus('loading');
      try {
          // Načítame master katalóg
          const masterRef = doc(db, 'settings', 'master_catalog');
          const snap = await getDoc(masterRef);

          if (snap.exists()) {
              const data = snap.data();
              const allMasterParts = (data.parts || []) as {p: string, d: string}[];
              const found = allMasterParts.find(m => m.p && m.p.toUpperCase() === partToFind);

              if (found) {
                  setMasterSearchStatus('found');
                  if (window.confirm(t('db_master_found'))) {
                      handleSelectPart(found.p);
                  }
              } else {
                  setMasterSearchStatus('not_found');
              }
          } else {
              setMasterSearchStatus('not_found');
          }
      } catch (err) {
          console.error("Master lookup failed", err);
          setMasterSearchStatus('not_found');
      }
  };

  const isExactMatch = useMemo(() => (parts || []).some(p => p && p.toLowerCase() === query.trim().toLowerCase()), [query, parts]);
  const hasWildcard = query.includes('*');

  // Booleans for state to avoid TS2367 errors due to narrowing in JSX
  const masterIsIdle = masterSearchStatus === 'idle';
  const masterIsLoading = masterSearchStatus === 'loading';
  const masterIsNotFound = masterSearchStatus === 'not_found';

  const reportIsIdle = reportStatus === 'idle';
  const reportIsLoading = reportStatus === 'loading';
  const reportIsSuccess = reportStatus === 'success';

  const showMasterLookup = query.trim() !== '' && !isExactMatch && !hasWildcard && (masterIsIdle || masterIsLoading);
  const showReportButton = onRequestPart && query.trim() !== '' && !isExactMatch && !hasWildcard && (masterIsNotFound || !reportIsIdle);

  return (
    <div className="relative" ref={containerRef}>
      <div className="relative">
        <span className="absolute inset-y-0 left-0 flex items-center pl-4">
          <SearchIcon className="h-5 w-5 text-gray-500" />
        </span>
        <input
          type="text"
          ref={inputRef}
          value={query}
          onChange={handleChange}
          onKeyDown={handleInternalKeyDown}
          onFocus={() => setIsDropdownVisible(true)}
          placeholder={placeholder || t('input_wildcard_hint')}
          className="w-full h-12 pl-12 pr-4 bg-gray-700 border border-gray-600 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base"
        />
      </div>

      {isDropdownVisible && filteredParts.length > 0 && (
        <div className="absolute z-[999] w-full mt-2 bg-gray-800 border-2 border-gray-600 rounded-2xl shadow-2xl max-h-72 overflow-y-auto">
          <ul className="divide-y divide-gray-700">
            {filteredParts.map((part, index) => (
              <li
                key={index}
                onClick={() => handleSelectPart(part)}
                className="px-6 py-5 text-gray-300 hover:bg-teal-600 hover:text-white cursor-pointer transition-colors duration-150 font-mono text-lg font-black"
              >
                {part}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Tlačidlo pre Master DB Lookup */}
      {showMasterLookup && (
          <div className="mt-2 animate-fade-in">
              <button
                type="button"
                onMouseDown={handleMasterLookup}
                disabled={masterIsLoading}
                className="w-full py-3 px-4 bg-indigo-600/20 border border-indigo-500/50 hover:bg-indigo-600/40 text-indigo-400 font-bold rounded-lg flex items-center justify-center gap-2 transition-all active:scale-95"
              >
                  {masterIsLoading ? (
                      <div className="w-4 h-4 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin"></div>
                  ) : <GlobeIcon className="w-4 h-4" />}
                  <span className="text-xs uppercase tracking-widest">{t('db_master_lookup')}</span>
              </button>
          </div>
      )}

      {showReportButton && (
        <div className="mt-2 animate-fade-in">
             <button
                type="button"
                onMouseDown={handleRequestClick}
                disabled={!reportIsIdle}
                className={`w-full py-4 px-4 font-bold rounded-lg shadow-md flex items-center justify-center gap-2 transition-all duration-200 hover:scale-[1.01] ${
                    reportIsSuccess 
                    ? 'bg-green-600 border border-green-500 text-white cursor-default' 
                    : reportIsLoading
                    ? 'bg-yellow-800 border border-yellow-700 text-yellow-200 cursor-wait'
                    : 'bg-yellow-700 hover:bg-yellow-600 border border-yellow-500 text-white'
                }`}
            >
                {reportIsLoading ? (
                     <span className="text-base">{t('report_btn_loading')}</span>
                ) : reportIsSuccess ? (
                     <span className="text-base">{t('report_btn_success')}</span>
                ) : (
                    <>
                        <PlusIcon className="w-6 h-6 text-yellow-200" />
                        <span className="text-base">{t('report_btn_idle')} <strong>{query}</strong></span>
                    </>
                )}
            </button>
            <p className="text-center text-sm text-gray-500 mt-2">
                {reportIsSuccess ? t('report_hint_success') : t('report_hint_idle')}
            </p>
        </div>
      )}

      {masterSearchStatus === 'not_found' && reportIsIdle && (
          <p className="text-center text-[10px] text-rose-500 font-bold uppercase tracking-widest mt-2 animate-pulse">
              {t('db_master_not_found')}
          </p>
      )}
    </div>
  );
});

export default PartNumberInput;

import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { DBItem, MapSector, PartRequest, BOMRequest, BOMComponent, MapObstacle, CSItem, QuickActionConfig, Instruction } from '../../types/appTypes';

export const useMasterData = () => {
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]);
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [mapObstacles, setMapObstacles] = useState<MapObstacle[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [quickActions, setQuickActions] = useState<QuickActionConfig[]>([]);
  const [instructions, setInstructions] = useState<Instruction[]>([]);

  const [customers, setCustomers] = useState<CSItem[]>([]);
  const [suppliers, setSuppliers] = useState<CSItem[]>([]);

  useEffect(() => {
    const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
        const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
        setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
    });
    const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
    const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));

    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, BOMComponent[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubQuickActions = onSnapshot(doc(db, 'settings', 'quick_actions'), (s) => {
        setQuickActions(s.exists() ? (s.data().items || []) : []);
    });

    const unsubObstacles = onSnapshot(doc(db, 'settings', 'map_layout'), (docSnap) => {
        if (docSnap.exists()) {
            setMapObstacles(docSnap.data().obstacles || []);
        } else {
            setMapObstacles([]);
        }
    });

    const unsubCustomers = onSnapshot(doc(db, 'CSDB', 'customers'), (s) => {
        setCustomers(s.exists() ? (s.data().items || []) : []);
    });
    const unsubSuppliers = onSnapshot(doc(db, 'CSDB', 'suppliers'), (s) => {
        setSuppliers(s.exists() ? (s.data().items || []) : []);
    });

    // POSILNENÝ LISTENER: Počúvame celú kolekciu 'instructions_library'
    // Každý dokument v nej predstavuje jednu kategóriu (PROD, LOG, atď.)
    const unsubInstructions = onSnapshot(collection(db, 'instructions_library'), (s) => {
      const allInsts: Instruction[] = [];
      s.docs.forEach(d => {
        const data = d.data();
        if (data.items && Array.isArray(data.items)) {
          allInsts.push(...data.items);
        }
      });
      setInstructions(allInsts);
    });

    return () => { 
        unsubWp(); unsubLogOps(); unsubSectors(); unsubPartReq(); unsubBomReq();
        unsubParts(); unsubBOM(); unsubObstacles();
        unsubCustomers(); unsubSuppliers(); unsubQuickActions();
        unsubInstructions();
    };
  }, []);

  const onAddInstruction = async (inst: Omit<Instruction, 'id' | 'updatedAt'>) => {
    const categoryDocId = inst.category;
    const newItem = { ...inst, id: crypto.randomUUID(), updatedAt: Date.now() };
    await setDoc(doc(db, 'instructions_library', categoryDocId), { 
      items: arrayUnion(newItem) 
    }, { merge: true });
  };

  const onUpdateInstruction = async (id: string, updates: Partial<Instruction>) => {
    // Keďže nevieme v ktorom dokumente (kategórii) inštrukcia je, najskôr ju musíme nájsť
    const oldInst = instructions.find(i => i.id === id);
    if (!oldInst) return;

    const oldCategory = oldInst.category;
    const newCategory = updates.category || oldCategory;

    // Ak sa zmenila kategória, musíme ju vymazať zo starého dokumentu a pridať do nového
    if (oldCategory !== newCategory) {
      const oldRef = doc(db, 'instructions_library', oldCategory);
      const newRef = doc(db, 'instructions_library', newCategory);

      const oldSnap = await getDoc(oldRef);
      if (oldSnap.exists()) {
        const filtered = (oldSnap.data().items || []).filter((i: any) => i.id !== id);
        await updateDoc(oldRef, { items: filtered });
      }

      const updatedObj = { ...oldInst, ...updates, updatedAt: Date.now() };
      await setDoc(newRef, { items: arrayUnion(updatedObj) }, { merge: true });
    } else {
      // Ak kategória ostáva, len aktualizujeme pole v danom dokumente
      const ref = doc(db, 'instructions_library', oldCategory);
      const snap = await getDoc(ref);
      if (snap.exists()) {
        const items = snap.data().items || [];
        const newItems = items.map((i: any) => i.id === id ? { ...i, ...updates, updatedAt: Date.now() } : i);
        await updateDoc(ref, { items: newItems });
      }
    }
  };

  const onDeleteInstruction = async (id: string) => {
    const inst = instructions.find(i => i.id === id);
    if (!inst) return;

    const ref = doc(db, 'instructions_library', inst.category);
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const items = snap.data().items || [];
      const newItems = items.filter((i: any) => i.id !== id);
      await updateDoc(ref, { items: newItems });
    }
  };

  const onAddQuickAction = async (config: Omit<QuickActionConfig, 'id'>) => {
      const newAction = { ...config, id: crypto.randomUUID() };
      await setDoc(doc(db, 'settings', 'quick_actions'), { items: arrayUnion(newAction) }, { merge: true });
  };

  const onUpdateQuickAction = async (id: string, updates: Partial<QuickActionConfig>) => {
      const ref = doc(db, 'settings', 'quick_actions');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const currentItems = snap.data().items || [];
          const newItems = currentItems.map((i: any) => i.id === id ? { ...i, ...updates } : i);
          await updateDoc(ref, { items: newItems });
      }
  };

  const onDeleteQuickAction = async (id: string) => {
      const ref = doc(db, 'settings', 'quick_actions');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().items || []).filter((i: any) => i.id !== id);
          await updateDoc(ref, { items: filtered });
      }
  };

  // CSDB Actions
  const onAddCSItem = async (category: 'customers' | 'suppliers', name: string, description: string = '') => {
      try {
          const newItem: CSItem = { id: crypto.randomUUID(), name: name.toUpperCase(), description };
          await setDoc(doc(db, 'CSDB', category), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onBatchAddCSItems = async (category: 'customers' | 'suppliers', lines: string[]) => {
      try {
          const itemsToAdd = lines.map(line => {
              if (!line.trim()) return null;
              const [n, d] = line.split(';');
              return { id: crypto.randomUUID(), name: n.trim().toUpperCase(), description: d ? d.trim() : '' };
          }).filter(Boolean);
          if (itemsToAdd.length > 0) {
              await setDoc(doc(db, 'CSDB', category), { items: arrayUnion(...itemsToAdd) }, { merge: true });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteCSItem = async (category: 'customers' | 'suppliers', id: string) => {
      try {
          const ref = doc(db, 'CSDB', category);
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const current = snap.data().items || [];
              const filtered = current.filter((i: any) => i.id !== id);
              await updateDoc(ref, { items: filtered });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteAllCSItems = async (category: 'customers' | 'suppliers') => {
      try { await setDoc(doc(db, 'CSDB', category), { items: [] }); } catch (e) { console.error(e); }
  };

  // Obstacles
  const onAddMapObstacle = async (obs: Omit<MapObstacle, 'id'>) => {
      const id = `obs_${Date.now()}`;
      await setDoc(doc(db, 'settings', 'map_layout'), { 
          obstacles: arrayUnion({ ...obs, id }) 
      }, { merge: true });
  };
  const onDeleteMapObstacle = async (id: string) => {
      const ref = doc(db, 'settings', 'map_layout');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().obstacles || []).filter((o: any) => o.id !== id);
          await updateDoc(ref, { obstacles: filtered });
      }
  };

  // Workplaces
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0, x: number = 0, y: number = 0, defaultSource?: string | null, defaultTarget?: string | null) => { 
      await addDoc(collection(db, 'logistics_operations'), { 
          value: val, 
          standardTime: time, 
          distancePx: dist, 
          coordX: x, 
          coordY: y,
          defaultSourceSectorId: defaultSource || null,
          defaultTargetSectorId: defaultTarget || null
      }); 
  };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { 
      await updateDoc(doc(db, 'logistics_operations', id), updates); 
  };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onDeleteAllLogisticsOperations = async () => {
      const snap = await getDocs(collection(db, 'logistics_operations'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  // Parts (Single Doc Pattern)
  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { 
            value: value.toUpperCase(), 
            description 
          };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { 
          itemsToAdd.push({ 
            value: p.trim().toUpperCase(), 
            description: d ? d.trim() : '' 
          }); 
        }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };
  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };
  const onDeleteAllParts = async () => { try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); } };

  // BOM (Single Doc Pattern - Optimized for Quota Guard)
  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = { 
              parent: parent.toUpperCase(), 
              child: child.toUpperCase(), 
              consumption: qty 
          };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { 
                  itemsToAdd.push({ 
                      parent: p.trim().toUpperCase(), 
                      child: c.trim().toUpperCase(), 
                      consumption: parseFloat(q?.replace(',', '.') || '0') 
                  }); 
              }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.map((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error(e); } };

  // Requests
  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeletePartRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'part_requests', id)); } catch(e) { console.error(e); }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeleteBOMRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'bom_requests', id)); } catch(e) { console.error(e); }
  };

  return {
    partsMap, bomMap, workplaces, logisticsOperations, mapSectors, mapObstacles, partRequests, bomRequests,
    customers, suppliers, quickActions, instructions,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation, onDeleteAllLogisticsOperations,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddMapObstacle, onDeleteMapObstacle,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onAddCSItem, onBatchAddCSItems, onDeleteCSItem, onDeleteAllCSItems,
    onAddQuickAction, onUpdateQuickAction, onDeleteQuickAction,
    onAddInstruction, onUpdateInstruction, onDeleteInstruction,
    onRequestPart, onDeletePartRequest, 
    onRequestBOM, onDeleteBOMRequest
  };
};

import { db } from '../firebase';
import { 
  collection, 
  addDoc, 
  doc, 
  updateDoc, 
  deleteDoc, 
  writeBatch, 
  getDocs, 
  getDoc, 
  query, 
  where,
  getCountFromServer 
} from 'firebase/firestore';
import { Task, PriorityLevel, Notification } from '../types/appTypes';

/**
 * Získanie ID aktuálneho týždňa pre šanón.
 */
export const getISOWeekId = () => {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  const weekNumber = 1 + Math.round(((date.getTime() - week1.getTime()) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
  return `SANON_${date.getFullYear()}_${weekNumber.toString().padStart(2, '0')}`;
};

export const taskService = {
  async addTask(data: Partial<Task>) {
    return await addDoc(collection(db, 'tasks'), {
      ...data,
      createdAt: Date.now(),
      status: data.partNumber === "Počítanie zásob" ? 'unpacked' : 'open',
      isDone: false,
      isMissing: false
    });
  },

  async updateTask(id: string, updates: Partial<Task>) {
    return await updateDoc(doc(db, 'tasks', id), updates);
  },

  async deleteTask(id: string) {
    return await deleteDoc(doc(db, 'tasks', id));
  },

  async getDocCount() {
    const coll = collection(db, 'tasks');
    const snapshot = await getCountFromServer(coll);
    return snapshot.data().count;
  },

  async toggleManualBlock(task: Task) {
    const newState = !task.isManualBlocked;
    const updates: any = { isManualBlocked: newState };
    if (newState) {
        updates.isInProgress = false;
        updates.inProgressBy = null;
        updates.priority = 'LOW';
    } else {
        updates.createdAt = Date.now();
    }
    return await this.updateTask(task.id, updates);
  },

  async finishAudit(task: Task, result: 'found' | 'missing', note: string, auditor: string, onNotif: (n: Partial<Notification>) => void) {
    const badgeText = result === 'found' ? `AUDIT (OK) - ${note}` : `AUDIT (NOK) - ${note}`;
    const updates: any = { 
        isAuditInProgress: false, 
        auditFinalBadge: badgeText, 
        auditBy: null, 
        auditResult: result === 'found' ? 'OK' : 'NOK', 
        auditNote: note, 
        auditedBy: auditor, 
        auditedAt: Date.now() 
    };

    if (result === 'found') { 
        updates.isMissing = false; 
    } else { 
        updates.isDone = true; 
        updates.status = 'audit_error'; 
        updates.completedBy = auditor; 
        updates.completedAt = Date.now(); 
        updates.isInProgress = false; 
    }

    await this.updateTask(task.id, updates);

    if (task.createdBy) {
        onNotif({ 
            partNumber: task.partNumber || 'Unknown', 
            reason: `AUDIT: ${result.toUpperCase()} - ${note}`, 
            reportedBy: auditor, 
            targetUser: task.createdBy 
        });
    }
  },

  async dailyClosing() {
    const q = query(collection(db, 'tasks'), where('isDone', '==', true));
    const snapshot = await getDocs(q);
    if (snapshot.empty) return { success: true, count: 0 };

    const completedTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    const draftRef = doc(db, 'settings', 'draft');
    const draftSnap = await getDoc(draftRef);
    const existingData = draftSnap.exists() ? (draftSnap.data().data || []) : [];

    const batch = writeBatch(db);
    batch.set(draftRef, { data: [...existingData, ...completedTasks] }, { merge: true });
    snapshot.docs.forEach(d => batch.delete(d.ref));
    await batch.commit();

    return { success: true, count: completedTasks.length };
  },

  async weeklyClosing() {
    const sanonId = getISOWeekId();
    const draftRef = doc(db, 'settings', 'draft');
    const draftSnap = await getDoc(draftRef);
    const draftTasks = draftSnap.exists() ? (draftSnap.data().data || []) : [];

    const q = query(collection(db, 'tasks'), where('isDone', '==', true));
    const activeSnap = await getDocs(q);
    const activeTasks = activeSnap.docs.map(doc => ({ id: doc.id, ...doc.data() }));

    const allToArchive = [...draftTasks, ...activeTasks];
    if (allToArchive.length === 0) return { success: true, count: 0, sanon: sanonId };

    const batch = writeBatch(db);
    batch.set(doc(db, 'sanony', sanonId), { tasks: allToArchive, createdAt: Date.now(), id: sanonId });
    batch.set(draftRef, { data: [] });
    activeSnap.docs.forEach(d => batch.delete(d.ref));
    await batch.commit();

    return { success: true, count: allToArchive.length, sanon: sanonId };
  }
};

import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../../firebase';
import { collection, onSnapshot, query, where, limit, doc, getDocs } from 'firebase/firestore';
import { Task, PriorityLevel, Notification, ScrapConfig, DBItem } from '../../types/appTypes';
import { PRIORITY_ORDER } from '../../constants/uiConstants';
import { taskService } from '../../services/taskService';

export const useTaskData = (
    isAuthenticated: boolean, 
    checkPermission: (perm: string) => boolean,
    onAddNotification: (n: Partial<Notification>) => void,
    scrapConfig?: ScrapConfig,
    logisticsOperations?: DBItem[]
) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);
  const isFirstLoad = useRef(true);
  const checkPermissionRef = useRef(checkPermission);

  useEffect(() => { checkPermissionRef.current = checkPermission; }, [checkPermission]);

  // 1. LISTENER PRE ŽIVÉ ÚLOHY
  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));

      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added' && checkPermissionRef.current('perm_play_sound')) {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3').play().catch(() => {});
                  }
              }
          });
      }
      isFirstLoad.current = false;

      setTasks(newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) return (b.completedAt || 0) - (a.completedAt || 0);
        if (a.isManualBlocked !== b.isManualBlocked) return (a.isManualBlocked ? 1 : 0) - (b.isManualBlocked ? 1 : 0);
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'], pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        return pA !== pB ? pA - pB : (a.createdAt || 0) - (b.createdAt || 0);
      }));
    });
  }, [isAuthenticated]);

  // 2. LISTENER PRE DRAFT
  useEffect(() => {
    return onSnapshot(doc(db, 'settings', 'draft'), (s) => {
      setDraftTasks(s.exists() ? (s.data().data || []) : []);
    });
  }, []);

  // 3. WRAPPERS PRE SERVICE
  const onAddTask = useCallback(async (
    pn: string, wp: string | null, qty: string, unit: string, prio: PriorityLevel, 
    isLog?: boolean, note?: string, isProd?: boolean, src?: string | null, tgt?: string | null,
    startNow?: boolean, isAct?: boolean
  ) => {
    const user = localStorage.getItem('app_user') || 'Unknown';

    let finalWorkplace = wp || '';
    let finalSource = src || null;
    let finalTarget = tgt || null;
    let finalIsLog = !!isLog;
    let finalIsProd = !!isProd;

    // Špeciálne ošetrenie pre šrot (Scrap)
    if (pn === "Váženie šrotu") {
        finalIsLog = true;
        finalIsProd = false; 

        if (scrapConfig?.scrapLogisticsOpId && logisticsOperations) {
            const foundOp = logisticsOperations.find(o => o.id === scrapConfig.scrapLogisticsOpId);
            if (foundOp) {
                finalWorkplace = foundOp.value;
                finalSource = foundOp.defaultSourceSectorId || null;
                finalTarget = foundOp.defaultTargetSectorId || null;
            }
        }
    }

    const taskData: any = {
        partNumber: pn || '',
        text: pn || '',
        workplace: finalWorkplace,
        quantity: qty || '0',
        quantityUnit: unit || 'pcs',
        priority: prio || 'NORMAL',
        isLogistics: finalIsLog,
        isProduction: finalIsProd,
        isActivity: !!isAct,
        createdBy: user,
        note: note || '',
        plate: finalIsLog ? (note || '') : '',
        sourceSectorId: finalSource,
        targetSectorId: finalTarget
    };

    // OKAMŽITÉ SPUSTENIE (Rýchle akcie / Inventúra / Šrot)
    if (startNow || pn === "Počítanie zásob" || pn === "Váženie šrotu") {
        taskData.isInProgress = true;
        taskData.inProgressBy = user;
        taskData.startedAt = Date.now();
    }

    return taskService.addTask(taskData);
  }, [scrapConfig, logisticsOperations]);

  const onUpdateTask = useCallback((id: string, up: Partial<Task>) => taskService.updateTask(id, up), []);
  const onDeleteTask = useCallback((id: string) => taskService.deleteTask(id), []);

  const onToggleTask = useCallback(async (id: string, sectorId?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const updates: any = { isDone: !task.isDone, completedAt: !task.isDone ? Date.now() : null, completedBy: !task.isDone ? user : null, status: !task.isDone ? 'completed' : 'open' };
      if (!task.isDone && sectorId) updates.pickedFromSectorId = sectorId;
      return taskService.updateTask(id, updates);
  }, [tasks]);

  const onToggleMissing = useCallback(async (id: string, reason?: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      const isMarking = !task.isMissing;
      const updates: any = { isMissing: isMarking, missingReason: isMarking ? (reason || 'Unknown') : null, missingReportedBy: isMarking ? user : null, isInProgress: false, inProgressBy: null };
      if (isMarking && task.createdBy) {
          onAddNotification({ partNumber: task.partNumber, reason: `CHÝBA: ${reason}`, reportedBy: user, targetUser: task.createdBy });
      }
      return taskService.updateTask(id, updates);
  }, [tasks, onAddNotification]);

  const onSetInProgress = useCallback(async (id: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const user = localStorage.getItem('app_user') || 'Unknown';
      return taskService.updateTask(id, task.isInProgress ? { isInProgress: false, inProgressBy: null } : { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
  }, [tasks]);

  const onToggleBlock = useCallback(async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    const isCurrentlyBlocked = !!task.isBlocked;
    return taskService.updateTask(id, {
        isBlocked: !isCurrentlyBlocked,
        blockedBy: !isCurrentlyBlocked ? user : null
    });
  }, [tasks]);

  const onExhaustSearch = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        searchExhausted: true,
        searchedBy: user
    });
  }, []);

  const onAddNote = useCallback(async (id: string, note: string) => {
    return taskService.updateTask(id, { note });
  }, []);

  const onMarkAsIncorrect = useCallback(async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    return taskService.updateTask(id, {
        isDone: true,
        status: 'incorrectly_entered',
        completedAt: Date.now(),
        completedBy: user,
        isInProgress: false,
        inProgressBy: null
    });
  }, []);

  const onStartAudit = useCallback((id: string) => taskService.updateTask(id, { isAuditInProgress: true, auditBy: localStorage.getItem('app_user'), isInProgress: false, inProgressBy: null }), []);
  const onFinishAudit = useCallback((id: string, res: 'found' | 'missing', note: string) => {
      const task = tasks.find(t => t.id === id);
      if (task) taskService.finishAudit(task, res, note, localStorage.getItem('app_user') || 'Unknown', onAddNotification);
  }, [tasks, onAddNotification]);

  return {
    tasks, draftTasks, onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onToggleMissing, onSetInProgress, onStartAudit, onFinishAudit, onToggleBlock, onExhaustSearch, onAddNote, onMarkAsIncorrect,
    onToggleManualBlock: (id: string) => { const t = tasks.find(x => x.id === id); if(t) taskService.toggleManualBlock(t); },
    onDailyClosing: taskService.dailyClosing, onWeeklyClosing: taskService.weeklyClosing,
    onGetDocCount: taskService.getDocCount,
    fetchSanons: async () => (await getDocs(collection(db, 'sanony'))).docs.map(d => d.data())
  };
};
